from lxml import etree

def process_soap_request(xml_data):
    # Configure parser to prevent XXE vulnerabilities
    parser = etree.XMLParser(resolve_entities=False, no_network=True, dtd_validation=True)

    try:
        # Parse the XML data
        root = etree.fromstring(xml_data, parser=parser)

        # Extract the SOAP body
        body = root.find('{http://schemas.xmlsoap.org/soap/envelope/}Body')
        if body is not None:
            # Extract and return the message body content
            return etree.tostring(body, pretty_print=True, encoding='unicode')
        else:
            raise ValueError("SOAP Body not found")
    except etree.XMLSyntaxError as e:
        raise ValueError(f"Invalid XML: {e}")

